sql:
SELECT COUNT(event_id) AS event_count
FROM weather_events
WHERE wind_speed > (SELECT AVG(wind_speed) FROM weather_events);

SELECT AVG(temperature) AS average_temperature
FROM weather_events
WHERE event_id = 1;

SELECT MAX(avg_temp) AS highest_avg_temp
FROM (
  SELECT AVG(temperature) AS avg_temp
  FROM weather_events
  GROUP BY condition_id
) AS condition_averages;

